#include <iostream>

int main() {
    int a{};
    int b{};
    std::cin >> a >> b;

    int quotient{a / b};
    int remainder{a % b};

    std::cout << "Quotient: "  << quotient  << "\n";
    std::cout << "Remainder: " << remainder << "\n";
    return 0;
}

