#include <iostream>

void computeStats(long long x, long long y) {
    std::cout << "Sum: "     << x + y << "\n";
    std::cout << "Diff: "    << x - y << "\n";
    std::cout << "Product: " << x * y << "\n";
}

int main() {
    long long x{};
    long long y{};
    std::cin >> x >> y;
    computeStats(x, y);
    return 0;
}
